import { ORIENTATION } from '../../../../constants.js';
import { ChartLegendOrientation } from '../../../../types/legend.js';
import { DEFAULT_ITEM_THICKNESS, DEFAULT_SEGMENT_SIZE } from '../constants.js';
import { SegmentPositionAndSize } from '../types/range-legend.internal.js';

export const getSegmentItemPositionAndSize = (
  orientation: ChartLegendOrientation,
  startPosition: number,
  size: number,
): SegmentPositionAndSize => {
  const itemPosition =
    size === 0 && startPosition > DEFAULT_SEGMENT_SIZE
      ? startPosition - DEFAULT_SEGMENT_SIZE
      : startPosition;

  if (orientation === ORIENTATION.Horizontal) {
    return {
      itemX: itemPosition,
      itemY: 0,
      itemHeight: DEFAULT_ITEM_THICKNESS,
      itemWidth: size || DEFAULT_SEGMENT_SIZE,
    };
  }

  return {
    itemX: 0,
    itemY: itemPosition,
    itemHeight: size || DEFAULT_SEGMENT_SIZE,
    itemWidth: DEFAULT_ITEM_THICKNESS,
  };
};
